import collections

def analyze_hierarchy(employee_data):
    # Build a graph representation of the hierarchy
    graph = collections.defaultdict(list)
    for employee in employee_data:
        employee_id, employee_name, manager_id = employee
        graph[manager_id].append((employee_id, employee_name))

    # Determine hierarchy levels
    levels = {}
    def dfs(node, level):
        if node not in levels:
            levels[node] = level
            for child, _ in graph[node]:
                dfs(child, level + 1)
    dfs(None, 1)

    # Count subordinates
    subordinate_counts = {}
    def count_subordinates(node):
        count = 0
        for child, _ in graph[node]:
            count += 1 + count_subordinates(child)
        subordinate_counts[node] = count
        return count
    for node in graph:
        count_subordinates(node)

    # Build manager chains
    manager_chains = {}
    def build_chain(node, chain):
        if node is None:
            manager_chains[chain[-1][0]] = chain
        else:
            for child, name in graph[node]:
                build_chain(child, chain + [(child, name)])
    build_chain(None, [])

    # Output results
    output = []
    for employee in employee_data:
        employee_id, employee_name, manager_id = employee
        output.append((
            employee_id,
            employee_name,
            levels.get(employee_id, None),
            subordinate_counts.get(employee_id, 0),
            ' > '.join(name for _, name in manager_chains.get(employee_id, [])),
        ))
    return output

